const http = require('http');
const https = require('https');
const url = require('url');
const crypto = require('crypto');

const PORT = process.env.PORT || 3000;
const API_KEY_HEADER = 'x-api-key';
const RATE_LIMIT_WINDOW = 60000;
const RATE_LIMIT_MAX_REQUESTS = 100;

const validApiKeys = new Set([
  process.env.API_KEY_1 || crypto.randomBytes(32).toString('hex'),
  process.env.API_KEY_2 || crypto.randomBytes(32).toString('hex')
]);

const rateLimitStore = new Map();
const ipBlacklist = new Set();

function cleanupRateLimitStore() {
  const now = Date.now();
  for (const [key, data] of rateLimitStore.entries()) {
    if (now - data.windowStart > RATE_LIMIT_WINDOW) {
      rateLimitStore.delete(key);
    }
  }
}

setInterval(cleanupRateLimitStore, 60000);

function checkRateLimit(identifier) {
  const now = Date.now();
  const record = rateLimitStore.get(identifier);

  if (!record) {
    rateLimitStore.set(identifier, {
      count: 1,
      windowStart: now
    });
    return true;
  }

  if (now - record.windowStart > RATE_LIMIT_WINDOW) {
    rateLimitStore.set(identifier, {
      count: 1,
      windowStart: now
    });
    return true;
  }

  if (record.count >= RATE_LIMIT_MAX_REQUESTS) {
    return false;
  }

  record.count++;
  return true;
}

function validateApiKey(apiKey) {
  if (!apiKey) return false;
  return validApiKeys.has(apiKey);
}

function getClientIp(req) {
  const forwarded = req.headers['x-forwarded-for'];
  if (forwarded) {
    return forwarded.split(',')[0].trim();
  }
  return req.socket.remoteAddress;
}

function sanitizeHeaders(headers) {
  const sanitized = {};
  const allowedHeaders = [
    'content-type',
    'authorization',
    'accept',
    'user-agent',
    'cache-control',
    'x-requested-with'
  ];

  for (const [key, value] of Object.entries(headers)) {
    const lowerKey = key.toLowerCase();
    if (allowedHeaders.includes(lowerKey)) {
      sanitized[key] = value;
    }
  }

  return sanitized;
}

function validateRequestPath(pathname) {
  if (pathname.includes('..')) return false;
  if (pathname.includes('//')) return false;
  if (pathname.match(/[<>'"]/)) return false;
  return true;
}

function setCorsHeaders(res) {
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'GET, POST, PUT, DELETE, PATCH, OPTIONS, HEAD');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type, Authorization, X-Requested-With, Accept, X-API-Key');
  res.setHeader('Access-Control-Max-Age', '86400');
  res.setHeader('Access-Control-Allow-Credentials', 'false');
}

function setSecurityHeaders(res) {
  res.setHeader('X-Content-Type-Options', 'nosniff');
  res.setHeader('X-Frame-Options', 'DENY');
  res.setHeader('X-XSS-Protection', '1; mode=block');
  res.setHeader('Strict-Transport-Security', 'max-age=31536000; includeSubDomains');
  res.setHeader('Content-Security-Policy', "default-src 'none'");
  res.setHeader('Referrer-Policy', 'no-referrer');
}

function sendError(res, statusCode, message) {
  setCorsHeaders(res);
  setSecurityHeaders(res);
  res.writeHead(statusCode, { 'Content-Type': 'application/json' });
  res.end(JSON.stringify({ error: message }));
}

function proxyRequest(req, res, targetUrl) {
  const parsedTarget = url.parse(targetUrl);
  const isHttps = parsedTarget.protocol === 'https:';
  const httpModule = isHttps ? https : http;

  const sanitizedHeaders = sanitizeHeaders(req.headers);
  sanitizedHeaders.host = parsedTarget.host;

  const options = {
    hostname: parsedTarget.hostname,
    port: parsedTarget.port || (isHttps ? 443 : 80),
    path: parsedTarget.path,
    method: req.method,
    headers: sanitizedHeaders,
    timeout: 30000
  };

  const proxyReq = httpModule.request(options, (proxyRes) => {
    setCorsHeaders(res);
    setSecurityHeaders(res);
    
    res.writeHead(proxyRes.statusCode, proxyRes.headers);
    proxyRes.pipe(res);
  });

  proxyReq.on('error', (error) => {
    console.error('Proxy request error:', error.message);
    sendError(res, 502, 'Bad Gateway');
  });

  proxyReq.on('timeout', () => {
    proxyReq.destroy();
    sendError(res, 504, 'Gateway Timeout');
  });

  req.pipe(proxyReq);
}

const server = http.createServer((req, res) => {
  const clientIp = getClientIp(req);

  if (ipBlacklist.has(clientIp)) {
    sendError(res, 403, 'Forbidden');
    return;
  }

  if (req.method === 'OPTIONS') {
    setCorsHeaders(res);
    setSecurityHeaders(res);
    res.writeHead(204);
    res.end();
    return;
  }

  const apiKey = req.headers[API_KEY_HEADER];
  if (!validateApiKey(apiKey)) {
    sendError(res, 401, 'Unauthorized: Invalid API Key');
    return;
  }

  const rateLimitKey = `${clientIp}:${apiKey}`;
  if (!checkRateLimit(rateLimitKey)) {
    sendError(res, 429, 'Too Many Requests');
    return;
  }

  const parsedUrl = url.parse(req.url);
  const pathname = parsedUrl.pathname;

  if (!validateRequestPath(pathname)) {
    sendError(res, 400, 'Bad Request: Invalid path');
    return;
  }

  const backendServices = {
    '/api/users': process.env.USER_SERVICE_URL || 'http://localhost:4001',
    '/api/products': process.env.PRODUCT_SERVICE_URL || 'http://localhost:4002',
    '/api/orders': process.env.ORDER_SERVICE_URL || 'http://localhost:4003'
  };

  let targetService = null;
  for (const [prefix, serviceUrl] of Object.entries(backendServices)) {
    if (pathname.startsWith(prefix)) {
      targetService = serviceUrl + pathname.substring(prefix.length) + (parsedUrl.search || '');
      break;
    }
  }

  if (!targetService) {
    sendError(res, 404, 'Not Found: Service not available');
    return;
  }

  proxyRequest(req, res, targetService);
});

server.listen(PORT, () => {
  console.log(`API Gateway running on port ${PORT}`);
  console.log('Security features enabled:');
  console.log('- API Key authentication');
  console.log('- Rate limiting');
  console.log('- Request validation');
  console.log('- Security headers');
  console.log('- CORS enabled for all origins');
});

process.on('SIGTERM', () => {
  console.log('SIGTERM received, shutting down gracefully');
  server.close(() => {
    console.log('Server closed');
    process.exit(0);
  });
});